import{_ as n,C as o,o as c,c as s,j as e,a as d,E as a,ag as l}from"./chunks/framework.HG0H2VLS.js";const k=JSON.parse('{"title":"NotificationBadge","description":"","frontmatter":{},"headers":[],"relativePath":"components/notification-badge.md","filePath":"components/notification-badge.md"}'),h={name:"components/notification-badge.md"},p={id:"notificationbadge",tabindex:"-1"};function g(b,t,u,m,f,x){const i=o("Badge"),r=o("ComponentDemo");return c(),s("div",null,[t[3]||(t[3]=e("hr",null,null,-1)),t[4]||(t[4]=e("h2",{id:"title-notificationbadge",tabindex:"-1"},[d("title: NotificationBadge "),e("a",{class:"header-anchor",href:"#title-notificationbadge","aria-label":'Permalink to "title: NotificationBadge"'},"​")],-1)),e("h1",p,[t[0]||(t[0]=d("NotificationBadge ",-1)),a(i,{type:"warning",text:"Control Centre"}),t[1]||(t[1]=d()),t[2]||(t[2]=e("a",{class:"header-anchor",href:"#notificationbadge","aria-label":'Permalink to "NotificationBadge <Badge type="warning" text="Control Centre" />"'},"​",-1))]),t[5]||(t[5]=e("blockquote",null,[e("p",null,"Bell trigger + overlaid count badge")],-1)),a(r,{src:"/demos/src/components/NotificationBadge/NotificationBadge.html"}),t[6]||(t[6]=l('<h2 id="origin" tabindex="-1">Origin <a class="header-anchor" href="#origin" aria-label="Permalink to &quot;Origin&quot;">​</a></h2><p>This component does <strong>not</strong> exist as a standalone component set in Figma. It was extracted from a repeating layer pattern in <code>CCHeader</code> named <code>Notification</code>:</p><table tabindex="0"><thead><tr><th>CCHeader variant</th><th>Notification node</th><th>Size</th><th>Bell icon size</th></tr></thead><tbody><tr><td>Desktop / Default</td><td><code>4095:3413</code></td><td>40px</td><td>20px</td></tr><tr><td>Desktop / Control</td><td><code>4095:3418</code></td><td>40px</td><td>20px</td></tr><tr><td>Desktop / Sub Text</td><td><code>4097:3411</code></td><td>40px</td><td>20px</td></tr><tr><td>Mobile / Default</td><td><code>4097:3565</code></td><td>32px</td><td>16px</td></tr><tr><td>Mobile / Control</td><td><code>4113:3433</code></td><td>32px</td><td>16px</td></tr><tr><td>Mobile / Sub Text</td><td><code>4110:3414</code></td><td>32px</td><td>16px</td></tr></tbody></table><p>Extracted as an atomic component because the pattern appears 6× across CCHeader and is a natural reusable unit anywhere a notification trigger appears.</p><hr><h2 id="variant-matrix" tabindex="-1">Variant matrix <a class="header-anchor" href="#variant-matrix" aria-label="Permalink to &quot;Variant matrix&quot;">​</a></h2><p>Single Size axis, 2 variants:</p><table tabindex="0"><thead><tr><th>Size</th><th>CSS modifier</th><th>Outer wrap</th><th>Bell icon</th><th>Badge dot</th></tr></thead><tbody><tr><td>Default</td><td>(none)</td><td>40px</td><td>20px (<code>--ai-icon-size-md</code>)</td><td>12px</td></tr><tr><td>Small</td><td><code>.btn--sm</code> (on inner button)</td><td>32px</td><td>16px (<code>--ai-icon-size-sm</code>)</td><td>12px</td></tr></tbody></table><p>The outer wrap is sized by the inner <code>.btn.btn--tertiary.btn--icon</code> (default) or <code>.btn.btn--tertiary.btn--icon.btn--sm</code> (small). NotificationBadge supplies the badge overlay only — sizing is delegated to the Button component.</p><hr><h2 id="css-class-mapping" tabindex="-1">CSS class mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS class mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Element</th><th>Class</th></tr></thead><tbody><tr><td>Wrapper</td><td><code>.notification-badge</code> (<code>&lt;span&gt;</code>)</td></tr><tr><td>Bell trigger</td><td><code>.btn.btn--tertiary.btn--icon</code> (Button component)</td></tr><tr><td>Bell icon</td><td><code>&lt;i data-lucide=&quot;bell&quot;&gt;</code></td></tr><tr><td>Count badge</td><td><code>.notification-badge__count</code> (<code>&lt;span&gt;</code>)</td></tr></tbody></table><p>The count <code>&lt;span&gt;</code> is optional. Omit it when there&#39;s nothing to notify (renders as just the bell button).</p><hr><h2 id="token-mapping" tabindex="-1">Token mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token mapping&quot;">​</a></h2><h3 id="bell-trigger-delegated-to-button" tabindex="-1">Bell trigger (delegated to Button) <a class="header-anchor" href="#bell-trigger-delegated-to-button" aria-label="Permalink to &quot;Bell trigger (delegated to Button)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>Background</td><td><code>--ai-btn-tertiary-bg</code> (transparent)</td></tr><tr><td>Icon colour</td><td><code>--ai-btn-tertiary-text</code> (inherits theme)</td></tr><tr><td>Size (default)</td><td><code>--ai-spacing-8</code> (40px, from <code>.btn--icon</code>)</td></tr><tr><td>Size (sm)</td><td><code>--ai-spacing-7</code> (32px, from <code>.btn--icon.btn--sm</code>)</td></tr><tr><td>Radius</td><td><code>--ai-radius-md</code> (8px, from <code>.btn</code>)</td></tr></tbody></table><h3 id="badge" tabindex="-1">Badge <a class="header-anchor" href="#badge" aria-label="Permalink to &quot;Badge&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Token</th><th>Notes</th></tr></thead><tbody><tr><td>Background</td><td><code>var(--ai-surface-error)</code></td><td>Resolves to Red 600 (#dc2626). Figma uses Red 500 (#ef4444) but Red 500 has no semantic token — see Token gaps.</td></tr><tr><td>Border</td><td><code>2px solid var(--ai-surface-primary)</code></td><td>Border colour matches the page bg, producing a &quot;halo&quot; against the parent. In CC the parent header bg (<code>--cc-header-secondary-bg</code>) is white = <code>--ai-surface-primary</code>.</td></tr><tr><td>Border radius</td><td><code>var(--ai-radius-full)</code></td><td>Fully circular</td></tr><tr><td>Min width / height</td><td><code>var(--ai-spacing-4)</code> (12px)</td><td>Square base; grows wider if count &gt; 1 digit</td></tr><tr><td>Text colour</td><td><code>var(--ai-text-invert)</code> (white)</td><td></td></tr><tr><td>Font family</td><td><code>var(--ai-font-body)</code></td><td>Inter</td></tr><tr><td>Font weight</td><td><code>var(--ai-font-bold)</code> (700)</td><td></td></tr><tr><td>Font size</td><td><code>8px</code></td><td><strong>Token gap</strong> — sub-token optical size, see below</td></tr><tr><td>Line-height</td><td><code>1</code></td><td></td></tr><tr><td>Padding</td><td><code>0 var(--ai-spacing-1)</code> (0 4px)</td><td>Horizontal only, for multi-digit counts</td></tr><tr><td>Position</td><td><code>top: 0; right: 0; transform: translate(25%, -25%)</code></td><td>Translate-based offset — size-agnostic top-right overhang. Figma uses raw <code>top: 4px right: 5px</code> (40px) and <code>top: 1px right: 2px</code> (32px). Translate is cleaner and matches the visual intent.</td></tr></tbody></table><hr><h2 id="token-gaps" tabindex="-1">Token gaps <a class="header-anchor" href="#token-gaps" aria-label="Permalink to &quot;Token gaps&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gap</th><th>Figma</th><th>Resolution</th></tr></thead><tbody><tr><td>Badge background</td><td>Red 500 / <code>#ef4444</code> (raw primitive, no <code>--ai-*</code> token)</td><td>Approved: use existing <code>--ai-surface-error</code> (Red 600 / <code>#dc2626</code>). Slightly darker than Figma. Worth raising with the designer to add <code>--ai-surface-error-bright</code> (Red 500).</td></tr><tr><td>Badge counter font-size</td><td>8px (no token at this size; smallest tokens are <code>--ai-font-fixed-xxs</code> = 11px and <code>--ai-font-fluid-xxs</code> = 12px)</td><td>Approved: use raw <code>8px</code> with comment. Sub-token optical size, similar exception class to border-widths and letter-spacing.</td></tr><tr><td>Badge position offsets</td><td><code>top: 4px right: 5px</code> (40px) and <code>top: 1px right: 2px</code> (32px) — only 4px maps to a token</td><td>Resolved by switching to translate-based offset (<code>translate(25%, -25%)</code>), which is size-agnostic and avoids the raw-px positions.</td></tr></tbody></table><hr><h2 id="accessibility" tabindex="-1">Accessibility <a class="header-anchor" href="#accessibility" aria-label="Permalink to &quot;Accessibility&quot;">​</a></h2><ul><li>The bell trigger is a <code>&lt;button type=&quot;button&quot;&gt;</code> with explicit <code>aria-label</code> describing the count (e.g. <code>&quot;Notifications, 2 unread&quot;</code>). The count is <strong>not</strong> read as part of the label when empty — supply a count-less label (<code>&quot;Notifications&quot;</code>) when omitting the badge.</li><li>The count <code>&lt;span&gt;</code> is <code>aria-hidden=&quot;true&quot;</code> because the count is already in the button&#39;s aria-label. This avoids duplicate announcements.</li><li>Focus styling is inherited from <code>.btn--tertiary:focus-visible</code>.</li></ul><hr><h2 id="history" tabindex="-1">History <a class="header-anchor" href="#history" aria-label="Permalink to &quot;History&quot;">​</a></h2><ul><li>2026-05-15: Initial component scaffold. Extracted from the repeating Notification layer in CCHeader (CC Hybrid Design System file). Token gaps documented for badge bg (Red 500 → falls back to Red 600), badge font-size (8px optical), and position offsets (resolved via translate-based offset).</li></ul><h2 id="figma" tabindex="-1">Figma <a class="header-anchor" href="#figma" aria-label="Permalink to &quot;Figma&quot;">​</a></h2><p><a href="https://www.figma.com/design/ETKqleZdpertwFEo40YB5n/Affino-CC-Hybrid--Design-System?node-id=4095-3413" target="_blank" rel="noreferrer">Open in Figma</a></p>',30))])}const B=n(h,[["render",g]]);export{k as __pageData,B as default};
